VALUES
  ('medical-tech-moex-07728', 'medical-tech', 'medical-tech-moex-107-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '關於人類 T 細胞白血病病毒（human T-cell leukemia virus, HTLV）之敘述，下列何者錯誤？', '["目前有分成HTLV-1、2、3與4型", "病毒基因體主要組成有gag、pol 與env", "臨床檢驗可以藉由PCR來鑑定與分型", "HTLV-2與成人 T 細胞白血病（adult T cell leukemia or lymphoma, ATLL）有密切相關"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:31+00:00", "source_pdf_sha1": "65eb64da0f87", "answer_pdf_sha1": "7866cd737d80", "source_family": "moex-gov-tw", "moex": {"exam_code": "107100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "107", "exam_name": "107年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸...", "original_question_number": 70, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-07729', 'medical-tech', 'medical-tech-moex-107-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列那一種病毒之結構具有雙層殼體（double-layered capsid）及雙股基因片段（double-stranded genomic segments）的特性？', '["小RNA病毒科（Picornaviridae）", "呼腸孤病毒科（Reoviridae）", "反轉錄病毒科（Retroviridae）", "披衣病毒科（Togaviridae）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:31+00:00", "source_pdf_sha1": "65eb64da0f87", "answer_pdf_sha1": "7866cd737d80", "source_family": "moex-gov-tw", "moex": {"exam_code": "107100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "107", "exam_name": "107年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸...", "original_question_number": 71, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-07730', 'medical-tech', 'medical-tech-moex-107-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '關於冠狀病毒（coronavirus）的敘述，何者錯誤？', '["具有non-segment，單股RNA基因體", "在電子顯微鏡下呈現皇冠狀，是由於病毒具有外套膜尖釘蛋白（spike protein）", "在臨床病毒分離常見的人類冠狀病毒是229E與OC43兩種病毒株", "229E與OC43在臨床上發現容易引起下呼吸道的感染而導致肺炎的發生"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:31+00:00", "source_pdf_sha1": "65eb64da0f87", "answer_pdf_sha1": "7866cd737d80", "source_family": "moex-gov-tw", "moex": {"exam_code": "107100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "107", "exam_name": "107年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸...", "original_question_number": 72, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-07731', 'medical-tech', 'medical-tech-moex-107-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列那些病毒可經由糞口途徑傳染（fecal-oral transmission）？①腸病毒（enterovirus）  ②輪狀病毒', '["僅①②③", "僅①②③④", "僅①②③⑤", "①②③④⑤"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:31+00:00", "source_pdf_sha1": "65eb64da0f87", "answer_pdf_sha1": "7866cd737d80", "source_family": "moex-gov-tw", "moex": {"exam_code": "107100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "107", "exam_name": "107年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸...", "original_question_number": 73, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-07732', 'medical-tech', 'medical-tech-moex-107-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '關於人類間質肺炎病毒（human metapneumovirus, HMPV）之敘述，何者正確？', '["屬於正黏液病毒科（Orthomyxoviridae）", "含多片段病毒基因體", "可以用恆河猴（rhesus）LLC-MK2細胞培養", "此病毒的G蛋白（G protein）參與被感染細胞之融合現象（syncytium formation）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:31+00:00", "source_pdf_sha1": "65eb64da0f87", "answer_pdf_sha1": "7866cd737d80", "source_family": "moex-gov-tw", "moex": {"exam_code": "107100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "107", "exam_name": "107年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸...", "original_question_number": 74, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-07733', 'medical-tech', 'medical-tech-moex-107-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '關於馬堡病毒（Marburg virus）之敘述，何者錯誤？', '["屬於絲狀病毒科（Filoviridae）", "屬於risk group 4 agent（RG 4）", "感染此類病毒常會造成凝血系統問題，導致出血", "目前只能仰賴症狀及血清學診斷，缺乏此類病毒核酸偵測方法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:31+00:00", "source_pdf_sha1": "65eb64da0f87", "answer_pdf_sha1": "7866cd737d80", "source_family": "moex-gov-tw", "moex": {"exam_code": "107100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "107", "exam_name": "107年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸...", "original_question_number": 75, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-07734', 'medical-tech', 'medical-tech-moex-107-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列何種病毒一般不容易造成呼吸道的感染？', '["腸病毒-D68型（enterovirus-D68）", "腸病毒-D70型（enterovirus-D70）", "鼻病毒-A100型（rhinovirus-A100）", "伊科病毒11型（echovirus 11）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:31+00:00", "source_pdf_sha1": "65eb64da0f87", "answer_pdf_sha1": "7866cd737d80", "source_family": "moex-gov-tw", "moex": {"exam_code": "107100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "107", "exam_name": "107年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸...", "original_question_number": 76, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-07735', 'medical-tech', 'medical-tech-moex-107-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '關於漢他病毒（Hantaan virus）的敘述，何者錯誤？', '["具有3段 single-stranded RNA genomes，且在細胞質內進行複製繁殖", "具有envelope glycoproteins 與 RNA-dependent-DNA polymerase", "感染漢他病毒肺症候群（Hantavirus pulmonary syndrome）之途徑，常因經由呼吸道吸入受漢他病毒感染 之鼠類的排泄物或分泌物所產生的空氣微粒", "屬於人畜共通疾病（zoonosis）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:31+00:00", "source_pdf_sha1": "65eb64da0f87", "answer_pdf_sha1": "7866cd737d80", "source_family": "moex-gov-tw", "moex": {"exam_code": "107100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "107", "exam_name": "107年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸...", "original_question_number": 77, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-07736', 'medical-tech', 'medical-tech-moex-107-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '有關德國麻疹病毒（rubella virus）之敘述，下列何者錯誤？', '["屬於Flaviviridae", "通常只感染人類，主要經由呼吸道飛沫傳染", "病毒之細胞培養不容易，主要做血清抗體檢測", "其疫苗是減毒性活疫苗"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:31+00:00", "source_pdf_sha1": "65eb64da0f87", "answer_pdf_sha1": "7866cd737d80", "source_family": "moex-gov-tw", "moex": {"exam_code": "107100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "107", "exam_name": "107年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸...", "original_question_number": 78, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-07737', 'medical-tech', 'medical-tech-moex-107-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '有關小RNA病毒（picornavirus）之敘述，下列何者錯誤？', '["其基因體是一負股RNA，病毒顆粒呈二十面體結構", "腸病毒可耐酸性（pH3 to pH9），故可在腸胃道複製", "鼻病毒通常會引起普通感冒（common cold），其適合生長溫度是33°Ｃ", "A型肝炎病毒是小RNA病毒科中的一員"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:31+00:00", "source_pdf_sha1": "65eb64da0f87", "answer_pdf_sha1": "7866cd737d80", "source_family": "moex-gov-tw", "moex": {"exam_code": "107100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "107", "exam_name": "107年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸...", "original_question_number": 79, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
